import { Component } from '@angular/core';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent {

}
<div>
    <h2>
        Welcome to the Hotel Reservation System!
    </h2>
    <button routerLink="/list" class="btn btn-primary m-2">View Reservations</button>
    <button routerLink="/new" class="btn btn-success m-2">New Reservation</button>
</div>
